1	//! AST-walking evaluator.
2	
3	use mlpl_array::{DenseArray, Shape};
4	use mlpl_autograd::{Tape, Tensor};
5	use mlpl_parser::{Expr, TensorCtorKind};
6	use mlpl_trace::{Trace, TraceEvent, TraceValue};
7	
8	use crate::env::Environment;
9	use crate::error::EvalError;
10	use crate::eval_ops::{eval_analysis_helper, eval_array_lit, eval_binop, eval_fncall, eval_svg};
11	use crate::value::Value;
12	
13	/// Evaluate a program (list of statements). Returns the last result as an array.
14	///
15	/// If the final value is a string, returns `EvalError::ExpectedArray`.
16	/// Use `eval_program_value` to handle both arrays and strings.
17	pub fn eval_program(stmts: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
18	    eval_program_value(stmts, env)?.into_array()
19	}
20	
21	/// Evaluate a program and return the final value (array or string).
22	pub fn eval_program_value(stmts: &[Expr], env: &mut Environment) -> Result<Value, EvalError> {
23	    run_program(stmts, env, None)
24	}
25	
26	/// Evaluate a program with tracing enabled. Returns the final array.
27	pub fn eval_program_traced(
28	    stmts: &[Expr],
29	    env: &mut Environment,
30	    trace: &mut Trace,
31	) -> Result<DenseArray, EvalError> {
32	    run_program(stmts, env, Some(trace))?.into_array()
33	}
34	
35	fn run_program(
36	    stmts: &[Expr],
37	    env: &mut Environment,
38	    mut trace: Option<&mut Trace>,
39	) -> Result<Value, EvalError> {
40	    if stmts.is_empty() {
41	        return Err(EvalError::EmptyInput);
42	    }
43	    let mut result = None;
44	    for stmt in stmts {
45	        result = Some(eval_expr(stmt, env, &mut trace)?);
46	    }
47	    result.ok_or(EvalError::EmptyInput)
48	}
49	
50	pub(crate) fn eval_expr(
51	    expr: &Expr,
52	    env: &mut Environment,
53	    trace: &mut Option<&mut Trace>,
54	) -> Result<Value, EvalError> {
55	    if let Expr::StrLit(s, _) = expr {
56	        return Ok(Value::Str(s.clone()));
57	    }
58	    if let Expr::FnCall { name, args, .. } = expr
59	        && name == "svg"
60	    {
61	        return eval_svg(args, env, trace).map(Value::Str);
62	    }
63	    if let Expr::FnCall { name, args, span } = expr
64	        && name == "grad"
65	    {
66	        let result = crate::grad::eval_grad(args, env)?;
67	        if let Some(t) = trace.as_mut() {
68	            let seq = t.events().len() as u64;
69	            t.push(TraceEvent {
70	                seq,
71	                op: "grad".into(),
72	                span: *span,
73	                inputs: vec![],
74	                output: TraceValue::from_array(&result),
75	            });
76	        }
77	        return Ok(Value::Array(result));
78	    }
79	    if let Expr::FnCall { name, args, .. } = expr
80	        && name == "linear"
81	    {
82	        let model = crate::model_dispatch::eval_linear(args, env)?;
83	        return Ok(Value::Model(model));
84	    }
85	    if let Expr::FnCall { name, args, .. } = expr
86	        && name == "chain"
87	    {
88	        let model = crate::model_dispatch::eval_chain(args, env)?;
89	        return Ok(Value::Model(model));
90	    }
91	    if let Expr::FnCall { name, args, .. } = expr
92	        && name == "residual"
93	    {
94	        let model = crate::model_dispatch::eval_residual(args, env)?;
95	        return Ok(Value::Model(model));
96	    }
97	    if let Expr::FnCall { name, args, .. } = expr
98	        && name == "rms_norm"
99	    {
100	        let model = crate::model_dispatch::eval_rms_norm(args, env)?;
101	        return Ok(Value::Model(model));
102	    }
103	    if let Expr::FnCall { name, args, .. } = expr
104	        && name == "attention"
105	    {
106	        let model = crate::model_dispatch::eval_attention(args, env)?;
107	        return Ok(Value::Model(model));
108	    }
109	    if let Expr::FnCall { name, args, .. } = expr
110	        && let Some(kind) = crate::model_dispatch::activation_kind(name)
111	    {
112	        if !args.is_empty() {
113	            return Err(EvalError::BadArity {
114	                func: name.into(),
115	                expected: 0,
116	                got: args.len(),
117	            });
118	        }
119	        return Ok(Value::Model(crate::model::ModelSpec::Activation(kind)));
120	    }
121	    if let Expr::FnCall { name, args, .. } = expr
122	        && name == "apply"
123	    {
124	        let result = crate::model_dispatch::eval_apply(args, env, trace)?;
125	        return Ok(Value::Array(result));
126	    }
127	    if let Expr::FnCall { name, args, span } = expr
128	        && (name == "momentum_sgd" || name == "adam")
129	    {
130	        let result = if name == "momentum_sgd" {
131	            crate::grad::eval_momentum_sgd(args, env)?
132	        } else {
133	            crate::grad::eval_adam(args, env)?
134	        };
135	        if let Some(t) = trace.as_mut() {
136	            let seq = t.events().len() as u64;
137	            t.push(TraceEvent {
138	                seq,
139	                op: name.clone(),
140	                span: *span,
141	                inputs: vec![],
142	                output: TraceValue::from_array(&result),
143	            });
144	        }
145	        return Ok(Value::Array(result));
146	    }
147	    if let Expr::FnCall { name, args, .. } = expr
148	        && let Some(result) = eval_analysis_helper(name, args, env, trace)
149	    {
150	        return result.map(Value::Str);
151	    }
152	    let (op_name, inputs, result) = match expr {
153	        Expr::IntLit(n, _) => ("literal", vec![], DenseArray::from_scalar(*n as f64)),
154	        Expr::FloatLit(f, _) => ("literal", vec![], DenseArray::from_scalar(*f)),
155	        Expr::StrLit(_, _) => unreachable!(),
156	        Expr::Ident(name, _) => {
157	            let r = env
158	                .get(name)
159	                .cloned()
160	                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
161	            ("ident", vec![], r)
162	        }
163	        Expr::ArrayLit(elems, _) => ("array_lit", vec![], eval_array_lit(elems, env, trace)?),
164	        Expr::UnaryNeg { operand, .. } => {
165	            let val = eval_expr(operand, env, trace)?.into_array()?;
166	            let r = DenseArray::from_scalar(-1.0).apply_binop(&val, |a, b| a * b)?;
167	            ("negate", vec![TraceValue::from_array(&val)], r)
168	        }
169	        Expr::Assign { name, value, .. } => {
170	            let is_param_ctor = matches!(
171	                value.as_ref(),
172	                Expr::TensorCtor {
173	                    kind: TensorCtorKind::Param,
174	                    ..
175	                }
176	            );
177	            let v = eval_expr(value, env, trace)?;
178	            match v {
179	                Value::Model(m) => {
180	                    env.models.insert(name.clone(), m);
181	                    let placeholder = DenseArray::from_scalar(0.0);
182	                    ("assign_model", vec![], placeholder)
183	                }
184	                Value::Str(_) => {
185	                    return Err(EvalError::Unsupported(
186	                        "assigning string values is not supported".into(),
187	                    ));
188	                }
189	                Value::Array(val) => {
190	                    env.set(name.clone(), val.clone());
191	                    if is_param_ctor {
192	                        env.mark_param(name);
193	                    }
194	                    ("assign", vec![TraceValue::from_array(&val)], val)
195	                }
196	            }
197	        }
198	        Expr::BinOp { op, lhs, rhs, .. } => eval_binop(op, lhs, rhs, env, trace)?,
199	        Expr::FnCall { name, args, .. } => eval_fncall(name, args, env, trace)?,
200	        Expr::TensorCtor { kind, shape, .. } => eval_tensor_ctor(*kind, shape, env, trace)?,
201	        Expr::Repeat { count, body, .. } => eval_repeat(count, body, env, trace)?,
202	        Expr::Train { count, body, .. } => eval_train(count, body, env, trace)?,
203	    };
204	    if let Some(t) = trace.as_mut() {
205	        let seq = t.events().len() as u64;
206	        t.push(TraceEvent {
207	            seq,
208	            op: op_name.into(),
209	            span: expr.span(),
210	            inputs,
211	            output: TraceValue::from_array(&result),
212	        });
213	    }
214	    Ok(Value::Array(result))
215	}
216	
217	fn eval_tensor_ctor(
218	    kind: TensorCtorKind,
219	    shape: &[Expr],
220	    env: &mut Environment,
221	    trace: &mut Option<&mut Trace>,
222	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
223	    let mut dims = Vec::with_capacity(shape.len());
224	    for dim_expr in shape {
225	        let arr = eval_expr(dim_expr, env, trace)?.into_array()?;
226	        if arr.rank() != 0 {
227	            return Err(EvalError::InvalidShapeDim);
228	        }
229	        let v = arr.data()[0];
230	        if v < 0.0 || v.fract() != 0.0 {
231	            return Err(EvalError::InvalidShapeDim);
232	        }
233	        dims.push(v as usize);
234	    }
235	    let zeros = DenseArray::zeros(Shape::new(dims));
236	    // Construct an autograd Tensor on a fresh tape. Step 005 will
237	    // route this through a tape stored in the environment so that
238	    // operations on the resulting array are recorded; for now we
239	    // simply return the underlying zero-initialized array.
240	    let tape = Tape::new();
241	    let _tensor = match kind {
242	        TensorCtorKind::Param => Tensor::param(tape, zeros.clone()),
243	        TensorCtorKind::Tensor => Tensor::leaf(tape, zeros.clone(), false),
