#[test]
fn positional_has_no_labels() {
    let ls = LabeledShape::positional(vec![2, 3]);
    assert_eq!(ls.dims(), &[2, 3]);
    assert_eq!(ls.labels(), &[None, None]);
    assert!(!ls.is_labeled());
}

