//! Dense array storage for MLPL.

use crate::error::ArrayError;
use crate::labels::LabeledShape;
use crate::shape::Shape;

/// A dense array with row-major contiguous storage.
///
/// `labels` is `Some` when axis names have been attached via the
/// Saga 11.5 `label(x, [...])` built-in or annotation syntax; fresh
/// arrays and every legacy construction path leave it `None`, which
/// means "positional" for every axis. Layout of `Vec<Option<String>>`
/// keeps an explicit `None` at each positional axis so that a
/// partially-labeled shape (e.g. `[None, Some("d_model")]`) can be
/// represented without the array having to forget the rank.
#[derive(Clone, Debug, PartialEq)]
pub struct DenseArray {
    pub(crate) shape: Shape,
    pub(crate) data: Vec<f64>,
    pub(crate) labels: Option<Vec<Option<String>>>,
}

impl DenseArray {
    /// Internal unchecked constructor: shape and data must already
    /// agree in length. Always starts with `labels = None`; callers
    /// that want labels chain `with_labels` afterward.
    pub(crate) fn from_raw_parts(shape: Shape, data: Vec<f64>) -> Self {
        Self {
            shape,
            data,
            labels: None,
        }
    }

    /// Create from a shape and data vector.
    ///
    /// Returns `DataLengthMismatch` if lengths disagree.
    pub fn new(shape: Shape, data: Vec<f64>) -> Result<Self, ArrayError> {
        let expected = shape.elem_count();
        if data.len() != expected {
            return Err(ArrayError::DataLengthMismatch {
                expected,
                got: data.len(),
            });
        }
        Ok(Self::from_raw_parts(shape, data))
    }

    /// Create a zero-filled array with the given shape.
    #[must_use]
    pub fn zeros(shape: Shape) -> Self {
        let len = shape.elem_count();
        Self::from_raw_parts(shape, vec![0.0; len])
    }

    /// Create a rank-0 (scalar) array.
    #[must_use]
    pub fn from_scalar(value: f64) -> Self {
        Self::from_raw_parts(Shape::scalar(), vec![value])
    }

    /// Create a rank-1 (vector) array.
    #[must_use]
    pub fn from_vec(data: Vec<f64>) -> Self {
        let shape = Shape::vector(data.len());
        Self::from_raw_parts(shape, data)
    }

    /// Borrow the shape.
    #[must_use]
    pub fn shape(&self) -> &Shape {
        &self.shape
    }

    /// Borrow the flat data slice.
    #[must_use]
    pub fn data(&self) -> &[f64] {
        &self.data
    }

    /// Borrow the optional per-axis label slice.
    ///
    /// `None` means every axis is positional (the common case).
    /// `Some(slice)` has one entry per axis, with inner `None` for
    /// positional axes in a partially-labeled shape.
    #[must_use]
    pub fn labels(&self) -> Option<&[Option<String>]> {
        self.labels.as_deref()
    }

    /// Returns a `LabeledShape` snapshot combining the raw dims with
    /// the current label state. Always well-defined: if the array is
    /// positional, every label is `None`.
    #[must_use]
    pub fn labeled_shape(&self) -> LabeledShape {
        match &self.labels {
            Some(lbls) => LabeledShape::new(self.shape.dims().to_vec(), lbls.clone()),
            None => LabeledShape::positional(self.shape.dims().to_vec()),
        }
    }

    /// Attach labels, returning the array.
    ///
    /// Panics if `labels.len() != rank`; labels must be in lock-step
    /// with the dim list. Labels are introduced explicitly in Phase 2
    /// of Saga 11.5 via the `label(x, [...])` built-in.
    #[must_use]
    pub fn with_labels(mut self, labels: Vec<Option<String>>) -> Self {
        assert_eq!(
            labels.len(),
            self.shape.rank(),
            "DenseArray::with_labels: labels must match rank"
        );
        self.labels = Some(labels);
        self
    }

    /// Apply a function to every element, returning a new array.
    #[must_use]
    pub fn map(&self, f: fn(f64) -> f64) -> Self {
        Self::from_raw_parts(
            self.shape.clone(),
            self.data.iter().map(|&x| f(x)).collect(),
        )
    }
}

